def score(result, args):
    items = args[0]
    seen = sorted(i for b in result for i in b)
    if seen != list(range(len(items))):
        return 0.0
    if any(sum(items[i] for i in b) > 1.0 + 1e-9 for b in result):
        return 0.0
    import math
    lower = math.ceil(sum(items) - 1e-9)
    return lower / max(len(result), 1)
